"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import {
  Heart,
  ArrowLeft,
  DollarSign,
  TrendingDown,
  Shield,
  Activity,
  Calculator,
  Download,
  AlertCircle,
  HelpCircle,
  Briefcase,
  CheckCircle2,
  FileText,
  Loader2,
  Search,
  Check,
} from "lucide-react";

interface TreatmentCost {
  hospitalName: string;
  hospitalCity: string;
  treatmentName: string;
  minCost: number;
  maxCost: number;
  insuranceCovered: boolean;
  isOpen24Hours: boolean;
}

interface Medicine {
  name: string;
  brandName: string;
  brandPrice: number;
  genericName: string;
  genericPrice: number;
  savings: number; // Percentage
}

export default function AffordabilityHubPage() {
  const router = useRouter();
  const { user, isLoading } = useAuth();

  const [activeTab, setActiveTab] = useState<"procedures" | "medicines" | "schemes" | "loans">("procedures");

  // Search & Filter State
  const [selectedTreatment, setSelectedTreatment] = useState("Angioplasty");
  const [treatmentOptions, setTreatmentOptions] = useState<string[]>([]);
  const [comparisons, setComparisons] = useState<TreatmentCost[]>([]);
  const [loading, setLoading] = useState(false);

  // Out-of-pocket calculator state
  const [hasInsurance, setHasInsurance] = useState(true);
  const [coverageLimit, setCoverageLimit] = useState(150000);
  const [deductible, setDeductible] = useState(10000);
  const [coPay, setCoPay] = useState(10); // Percentage

  // Generic Medicines Search State
  const [medicineSearch, setMedicineSearch] = useState("");
  const medicinesDb: Medicine[] = [
    { name: "Paracetamol (500mg)", brandName: "Crocin Pain Relief", brandPrice: 42, genericName: "Generic Paracetamol", genericPrice: 9, savings: 78 },
    { name: "Atorvastatin (10mg)", brandName: "Lipitor Cardiovascular", brandPrice: 320, genericName: "Generic Atorvastatin", genericPrice: 45, savings: 85 },
    { name: "Metformin (500mg)", brandName: "Glucophage Diabetes", brandPrice: 110, genericName: "Generic Metformin", genericPrice: 18, savings: 83 },
    { name: "Amoxicillin (250mg)", brandName: "Novamox Antibiotic", brandPrice: 140, genericName: "Generic Amoxicillin", genericPrice: 28, savings: 80 },
    { name: "Pantoprazole (40mg)", brandName: "Pan-D Acid Relief", brandPrice: 180, genericName: "Generic Pantoprazole", genericPrice: 35, savings: 80 },
  ];

  // Ayushman Bharat check
  const [incomeLevel, setIncomeLevel] = useState("low");
  const [hasRationCard, setHasRationCard] = useState(false);
  const [isAyushmanEligible, setIsAyushmanEligible] = useState<boolean | null>(null);

  // EMI estimator
  const [loanAmount, setLoanAmount] = useState(100000);
  const [loanTenure, setLoanTenure] = useState(12); // Months
  const [emiEstimate, setEmiEstimate] = useState(0);

  // Fetch treatment cost records
  useEffect(() => {
    async function loadComparisons() {
      try {
        setLoading(true);
        const res = await fetch("/api/hospitals");
        const data = await res.json();
        if (data.success) {
          const list: TreatmentCost[] = [];
          const treatmentsSet = new Set<string>();

          data.data.forEach((h: any) => {
            h.treatmentCosts?.forEach((tc: any) => {
              treatmentsSet.add(tc.treatmentName);
              if (tc.treatmentName.toLowerCase() === selectedTreatment.toLowerCase()) {
                list.push({
                  hospitalName: h.name,
                  hospitalCity: h.city,
                  treatmentName: tc.treatmentName,
                  minCost: tc.minCost,
                  maxCost: tc.maxCost,
                  insuranceCovered: tc.insuranceCovered,
                  isOpen24Hours: h.isOpen24Hours,
                });
              }
            });
          });

          setTreatmentOptions(Array.from(treatmentsSet));
          setComparisons(list.sort((a, b) => a.minCost - b.minCost));
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    loadComparisons();
  }, [selectedTreatment]);

  // Recalculate EMI
  useEffect(() => {
    const rate = 11.5 / 12 / 100; // 11.5% interest rate
    const emi = (loanAmount * rate * Math.pow(1 + rate, loanTenure)) / (Math.pow(1 + rate, loanTenure) - 1);
    setEmiEstimate(Math.round(emi));
  }, [loanAmount, loanTenure]);

  // Ayushman Bharat Eligibility Logic
  const handleCheckAyushman = (e: React.FormEvent) => {
    e.preventDefault();
    if (incomeLevel === "low" || hasRationCard) {
      setIsAyushmanEligible(true);
    } else {
      setIsAyushmanEligible(false);
    }
  };

  // Out of pocket calculation helper
  const calculateOutOfPocket = (avgCost: number) => {
    if (!hasInsurance) return avgCost;
    if (avgCost <= deductible) return avgCost;
    
    const coverable = Math.min(avgCost, coverageLimit) - deductible;
    const patientCoPay = coverable * (coPay / 100);
    const nonCovered = avgCost > coverageLimit ? avgCost - coverageLimit : 0;
    
    return deductible + patientCoPay + nonCovered;
  };

  const handleDownloadReport = () => {
    alert("Downloading cost comparison report as PDF...");
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <Loader2 className="w-8 h-8 text-primary-600 animate-spin" />
      </div>
    );
  }

  const filteredMedicines = medicinesDb.filter(
    (m) =>
      m.name.toLowerCase().includes(medicineSearch.toLowerCase()) ||
      m.brandName.toLowerCase().includes(medicineSearch.toLowerCase()) ||
      m.genericName.toLowerCase().includes(medicineSearch.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-surface-secondary pb-12">
      {/* Header */}
      <header className="bg-white border-b border-border sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.push("/dashboard")}
              className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <span className="text-lg font-bold text-text-primary">Affordability Hub</span>
          </div>
          <button
            onClick={handleDownloadReport}
            className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-surface-secondary hover:bg-border text-text-primary text-xs font-semibold rounded-lg transition-colors cursor-pointer"
          >
            <Download className="w-3.5 h-3.5" /> Download Report
          </button>
        </div>
      </header>

      {/* Main Grid */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-8">
        
        {/* Banner introduction */}
        <div>
          <h1 className="text-2xl sm:text-3xl font-extrabold text-text-primary tracking-tight">Healthcare Affordability Hub</h1>
          <p className="text-sm text-text-secondary mt-1 max-w-2xl leading-relaxed">
            Compare treatment costs, identify cheap generic drug alternatives, evaluate health scheme eligibility, and estimate out-of-pocket expenses.
          </p>
        </div>

        {/* Tab Selectors */}
        <div className="flex border-b border-border bg-white rounded-2xl px-4 pt-2">
          {(
            [
              { id: "procedures", label: "Treatment Cost Finder" },
              { id: "medicines", label: "Generic Medicine Finder" },
              { id: "schemes", label: "Ayushman Bharat Check" },
              { id: "loans", label: "Medical Loan Planner" },
            ] as const
          ).map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-4 py-3 text-xs sm:text-sm font-semibold border-b-2 cursor-pointer transition-colors -mb-px ${
                activeTab === tab.id
                  ? "border-primary-600 text-primary-600"
                  : "border-transparent text-text-secondary hover:text-text-primary"
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Tab Content Panels */}
        <div className="bg-white border border-border rounded-2xl p-6 shadow-xs">
          
          {activeTab === "procedures" && (
            <div className="grid lg:grid-cols-3 gap-8">
              {/* Cost comparison list */}
              <div className="lg:col-span-2 space-y-6">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 border-b border-border pb-4">
                  <div>
                    <h3 className="font-bold text-text-primary text-sm uppercase tracking-wider">Treatment Cost Comparison</h3>
                    <span className="text-[10px] text-text-muted">Compare treatment prices across partner hospitals</span>
                  </div>

                  <select
                    value={selectedTreatment}
                    onChange={(e) => setSelectedTreatment(e.target.value)}
                    className="text-xs border border-border rounded-xl px-3 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500 font-semibold"
                  >
                    {treatmentOptions.map((t) => (
                      <option key={t} value={t}>
                        {t}
                      </option>
                    ))}
                    {treatmentOptions.length === 0 && <option value="Angioplasty">Angioplasty</option>}
                  </select>
                </div>

                {loading ? (
                  <div className="flex items-center justify-center py-10 gap-2">
                    <Loader2 className="w-4 h-4 text-primary-600 animate-spin" />
                    <span className="text-xs text-text-secondary">Comparing prices...</span>
                  </div>
                ) : comparisons.length === 0 ? (
                  <div className="text-center py-10 text-text-muted text-xs">
                    No pricing records listed for this procedure.
                  </div>
                ) : (
                  <div className="overflow-hidden border border-border rounded-xl">
                    <table className="w-full text-left border-collapse text-xs sm:text-sm">
                      <thead>
                        <tr className="bg-surface-secondary/50 border-b border-border text-text-secondary font-semibold">
                          <th className="p-3">Hospital Facility</th>
                          <th className="p-3">Avg Cost Range</th>
                          <th className="p-3">Insurance Scope</th>
                          <th className="p-3">Out-of-pocket Est.</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-border text-xs">
                        {comparisons.map((c, i) => {
                          const avg = (c.minCost + c.maxCost) / 2;
                          const outOfPocket = calculateOutOfPocket(avg);
                          
                          return (
                            <tr key={i} className="hover:bg-surface-secondary/10">
                              <td className="p-3 font-semibold text-text-primary">
                                <div>{c.hospitalName}</div>
                                <div className="text-[10px] text-text-muted font-normal mt-0.5">{c.hospitalCity}</div>
                              </td>
                              <td className="p-3 font-semibold text-text-primary">
                                ₹{c.minCost.toLocaleString()} - ₹{c.maxCost.toLocaleString()}
                              </td>
                              <td className="p-3">
                                {c.insuranceCovered ? (
                                  <span className="text-[10px] px-2 py-0.5 bg-emerald-50 text-emerald-700 font-bold rounded">Yes</span>
                                ) : (
                                  <span className="text-[10px] px-2 py-0.5 bg-surface-secondary text-text-muted font-medium rounded">No</span>
                                )}
                              </td>
                              <td className="p-3 font-extrabold text-primary-600">
                                ₹{outOfPocket.toLocaleString()}
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>

              {/* Deductible Calculator */}
              <div className="space-y-6 border-l border-border pl-6">
                <div>
                  <h3 className="font-bold text-text-primary text-sm uppercase tracking-wider flex items-center gap-1.5">
                    <Calculator className="w-4 h-4 text-primary-600" /> Insurance Parameters
                  </h3>
                  <p className="text-[10px] text-text-muted mt-0.5">Define policy coverages for out-of-pocket checks</p>
                </div>

                <div className="space-y-4 text-xs">
                  <label className="flex items-center gap-2 font-semibold text-text-primary cursor-pointer select-none">
                    <input
                      type="checkbox"
                      checked={hasInsurance}
                      onChange={(e) => setHasInsurance(e.target.checked)}
                      className="w-4 h-4 rounded text-primary-600"
                    />
                    <span>Active Health Insurance policy</span>
                  </label>

                  {hasInsurance && (
                    <div className="space-y-4 pt-4 border-t border-border">
                      <div className="space-y-1.5">
                        <label className="text-[10px] font-bold text-text-muted uppercase tracking-wider block">Coverage Limit (₹)</label>
                        <input
                          type="number"
                          value={coverageLimit}
                          onChange={(e) => setCoverageLimit(Math.max(0, parseInt(e.target.value) || 0))}
                          className="w-full text-xs border border-border rounded-xl px-3 py-2 bg-white text-text-primary font-bold"
                        />
                      </div>

                      <div className="space-y-1.5">
                        <label className="text-[10px] font-bold text-text-muted uppercase tracking-wider block">Deductible (₹)</label>
                        <input
                          type="number"
                          value={deductible}
                          onChange={(e) => setDeductible(Math.max(0, parseInt(e.target.value) || 0))}
                          className="w-full text-xs border border-border rounded-xl px-3 py-2 bg-white text-text-primary font-bold"
                        />
                      </div>

                      <div className="space-y-1.5">
                        <label className="text-[10px] font-bold text-text-muted uppercase tracking-wider block">Co-Payment (%)</label>
                        <input
                          type="number"
                          max={100}
                          min={0}
                          value={coPay}
                          onChange={(e) => setCoPay(Math.max(0, Math.min(100, parseInt(e.target.value) || 0)))}
                          className="w-full text-xs border border-border rounded-xl px-3 py-2 bg-white text-text-primary font-bold"
                        />
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}

          {activeTab === "medicines" && (
            <div className="space-y-6">
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                  <h3 className="font-bold text-text-primary text-sm uppercase tracking-wider">Medicine Savings Directory</h3>
                  <p className="text-[10px] text-text-muted mt-0.5">Find generic alternatives and calculate cost savings</p>
                </div>

                <div className="relative w-full sm:w-64">
                  <Search className="absolute left-3 top-2.5 h-4 w-4 text-text-muted" />
                  <input
                    type="text"
                    placeholder="Search medicine name..."
                    value={medicineSearch}
                    onChange={(e) => setMedicineSearch(e.target.value)}
                    className="w-full text-xs pl-9 pr-3 py-2 border border-border rounded-xl bg-white text-text-primary"
                  />
                </div>
              </div>

              <div className="overflow-hidden border border-border rounded-xl">
                <table className="w-full text-left border-collapse text-xs sm:text-sm">
                  <thead>
                    <tr className="bg-surface-secondary/50 border-b border-border text-text-secondary font-semibold">
                      <th className="p-3">Salt Name / Drug Type</th>
                      <th className="p-3">Popular Brand Price</th>
                      <th className="p-3">Generic Alternative Price</th>
                      <th className="p-3 text-emerald-600 font-bold">Total Savings (%)</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-border text-xs">
                    {filteredMedicines.map((med, i) => (
                      <tr key={i} className="hover:bg-surface-secondary/10">
                        <td className="p-3 font-semibold text-text-primary">
                          <div>{med.name}</div>
                        </td>
                        <td className="p-3 text-text-secondary">
                          <div>{med.brandName}</div>
                          <span className="font-bold text-text-primary text-xs">₹{med.brandPrice}</span>
                        </td>
                        <td className="p-3 text-emerald-600 font-bold">
                          <div>{med.genericName}</div>
                          <span className="text-emerald-700 text-xs">₹{med.genericPrice}</span>
                        </td>
                        <td className="p-3 font-extrabold text-emerald-600 text-base">
                          {med.savings}% Save
                        </td>
                      </tr>
                    ))}
                    {filteredMedicines.length === 0 && (
                      <tr>
                        <td colSpan={4} className="text-center py-6 text-text-muted">
                          No matching medicines found.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === "schemes" && (
            <div className="space-y-6 max-w-xl mx-auto">
              <div>
                <h3 className="font-bold text-text-primary text-sm uppercase tracking-wider flex items-center gap-2">
                  <Shield className="w-5 h-5 text-emerald-600" /> PMJAY (Ayushman Bharat) Eligibility Check
                </h3>
                <p className="text-xs text-text-muted mt-0.5">Determine if you are eligible for the ₹5 Lakh free health cover scheme.</p>
              </div>

              <form onSubmit={handleCheckAyushman} className="space-y-4 text-xs">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-text-muted uppercase tracking-wider block">Income Group</label>
                  <select
                    value={incomeLevel}
                    onChange={(e) => setIncomeLevel(e.target.value)}
                    className="w-full text-xs border border-border rounded-xl px-3 py-2 bg-white text-text-primary"
                  >
                    <option value="low">Below Poverty Line (BPL) / Low Income</option>
                    <option value="mid">Middle Class (Averaging &gt; 2.5 LPA)</option>
                    <option value="high">High Class (&gt; 8 LPA)</option>
                  </select>
                </div>

                <label className="flex items-center gap-2.5 font-semibold text-text-primary cursor-pointer select-none">
                  <input
                    type="checkbox"
                    checked={hasRationCard}
                    onChange={(e) => setHasRationCard(e.target.checked)}
                    className="w-4 h-4 rounded text-primary-600"
                  />
                  <span>Hold active Priority Household (PHH) or Antyodaya Ration Card</span>
                </label>

                <button
                  type="submit"
                  className="w-full py-2.5 bg-primary-600 hover:bg-primary-700 text-white font-bold rounded-xl transition-all shadow-xs text-xs cursor-pointer"
                >
                  Evaluate Eligibility
                </button>
              </form>

              {isAyushmanEligible !== null && (
                <div
                  className={`p-4 border rounded-2xl flex items-start gap-2.5 text-xs font-semibold animate-slide-up ${
                    isAyushmanEligible
                      ? "bg-emerald-50 border-emerald-200 text-emerald-700"
                      : "bg-red-50 border-red-200 text-red-700"
                  }`}
                >
                  <CheckCircle2 className="w-5 h-5 flex-shrink-0" />
                  <div>
                    {isAyushmanEligible ? (
                      <>
                        <span className="block font-bold">You might be eligible!</span>
                        <span className="block font-medium mt-0.5 text-emerald-600">
                          Based on your profile, you can register under SECC criteria at any government hospital center.
                        </span>
                      </>
                    ) : (
                      <>
                        <span className="block font-bold">Not Eligible under default criteria</span>
                        <span className="block font-medium mt-0.5 text-red-500">
                          SECC criteria lists target weaker sections. Check other state-wise insurance policies.
                        </span>
                      </>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === "loans" && (
            <div className="space-y-6 max-w-xl mx-auto">
              <div>
                <h3 className="font-bold text-text-primary text-sm uppercase tracking-wider flex items-center gap-2">
                  <Briefcase className="w-5 h-5 text-amber-600" /> Low-Interest Medical Loan Estimator
                </h3>
                <p className="text-xs text-text-muted mt-0.5">Plan your healthcare EMIs with partnered zero-cost loan options.</p>
              </div>

              <div className="space-y-5 text-xs">
                <div className="space-y-1.5">
                  <div className="flex justify-between font-semibold text-text-primary">
                    <span>Required Loan Amount</span>
                    <span>₹{loanAmount.toLocaleString()}</span>
                  </div>
                  <input
                    type="range"
                    min={10000}
                    max={500000}
                    step={5000}
                    value={loanAmount}
                    onChange={(e) => setLoanAmount(parseInt(e.target.value))}
                    className="w-full accent-primary-600 cursor-pointer"
                  />
                </div>

                <div className="space-y-1.5">
                  <div className="flex justify-between font-semibold text-text-primary">
                    <span>Repayment Tenure</span>
                    <span>{loanTenure} Months</span>
                  </div>
                  <input
                    type="range"
                    min={3}
                    max={36}
                    step={3}
                    value={loanTenure}
                    onChange={(e) => setLoanTenure(parseInt(e.target.value))}
                    className="w-full accent-primary-600 cursor-pointer"
                  />
                </div>

                <div className="bg-surface-secondary/60 border border-border rounded-2xl p-4 flex justify-between items-center text-xs">
                  <div>
                    <span className="text-text-muted block font-bold">Estimated EMI</span>
                    <span className="text-[10px] text-text-muted mt-0.5 block">(Assumed Rate: 11.5% p.a.)</span>
                  </div>
                  <span className="text-lg font-extrabold text-text-primary">
                    ₹{emiEstimate.toLocaleString()} / month
                  </span>
                </div>
              </div>
            </div>
          )}

        </div>
      </main>
    </div>
  );
}
